ee:variables.ee:set-variable:
%dw 2.0
import * from java!com::governanceplus::reviewermule::ruleengine::PomDependencyValidator
output application/java
---
if (vars.pomContent == null) []
else do {
    var rulesJson = write(vars.applicablePomRules map ((r) -> { artifactId: r.ARTIFACT_ID, minVersion: r.MIN_VERSION }), "application/json")
    ---
    read(validatePomRulesAsJson(vars.pomContent, rulesJson), "application/json")
}

ee:message.ee:set-payload:
%dw 2.0
output application/json
var allViolations = (vars.xmlViolations default []) ++ (vars.pomViolations default []) ++ (vars.swaggerViolations default [])
var ruleMeta = (vars.xmlRuleRows map (r) -> { id: r.ID as String, description: r.DESCRIPTION, category: r.CATEGORY, severity: r.SEVERITY })
    ++ (vars.swaggerRuleRows map (r) -> { id: r.ID as String, description: r.DESCRIPTION, category: r.CATEGORY, severity: r.SEVERITY })
fun lookupMeta(ruleId) = (ruleMeta filter ($.id == (ruleId as String)))[0] default null
fun mapSeverity(raw) =
    if (raw == null) "MAJOR"
    else do {
        var upperRaw = upper(raw as String)
        ---
        if (contains(upperRaw, "CRIT")) "CRITICAL"
        else if (contains(upperRaw, "ERROR") or contains(upperRaw, "MAJOR")) "MAJOR"
        else "MINOR"
    }
fun toFinding(v) = do {
    var meta = lookupMeta(v.ruleId)
    ---
    if (meta != null)
        {
            rule: meta.description,
            category: meta.category,
            status: "FAIL",
            severity: mapSeverity(meta.severity),
            file: if (v.line >= 0) ((v.file as String) ++ ":" ++ (v.line as String)) else v.file,
            explanation: v.message,
            recommendation: ""
        }
    else
        {
            rule: "Dependency version requirement: " ++ (v.ruleId as String),
            category: "Dependencies",
            status: "FAIL",
            severity: "MAJOR",
            file: v.file,
            explanation: v.message,
            recommendation: ""
        }
}
var findings = allViolations map ((v) -> toFinding(v))
---
{
    summary: "Rule-engine review: " ++ (sizeOf(findings) as String) ++ " violation(s) found across Mule XML flows, pom.xml, and Swagger/OpenAPI specs.",
    findings: findings
}
